public class ThreeSum { public static java.util.List<java.util.List<Integer>> threeSum(int[] nums) { java.util.List<java.util.List<Integer>> result = new java.util.ArrayList<>(); java.util.Arrays.sort(nums); for(int i = 0; i < nums.length; i++) { int left = i + 1, right = nums.length - 1; while(left < right) { int sum = nums[i] + nums[left] + nums[right]; if(sum == 0) { result.add(java.util.Arrays.asList(nums[i], nums[left], nums[right])); left++; right--; } else if(sum < 0) left++; else right--; } } return result; } }